import React from "react";
import styles from "./mega-menu.module.css";
import NavList from "../nav-list";

const MegaMenu = () => {
  return (
    <div className={styles.mega_menu}>
      <div className={styles.mega_menu_container}>
        <NavList />
      </div>
    </div>
  );
};

export default MegaMenu;
